mapper.insert:
INSERT INTO payment_pass (
pay_no,
pass_no,
item_name
)
VALUES (
#{payNo},
#{passNo},
#{itemName}
)

mapper.select:
SELECT COUNT(*)
FROM user_pass_wallet
WHERE user_id = #{userId}

mapper.insert:
INSERT INTO user_pass_wallet (
user_id, remaining_count, total_purchased, pass_no
)
VALUES (
#{userId},
#{reviewCnt},
#{reviewCnt},
#{passNo}
)

mapper.update:
UPDATE user_pass_wallet
SET
remaining_count = remaining_count + #{reviewCnt},
total_purchased = total_purchased + #{reviewCnt},
pass_no = #{passNo}
WHERE user_id = #{userId}

mapper.insert:
INSERT INTO payment_registration (
pay_no,
company_no
)
VALUES (
#{payNo},
#{companyNo}
)

mapper.update:
UPDATE payment
SET pay_status='CANCEL'
WHERE pay_no=#{payNo}

UPDATE payment_pass
SET status='REFUND'
WHERE pay_no=#{payNo}

mapper.select:
SELECT U.coupon_code AS couponCode, C.coupon_name AS couponName, C.discount_rate AS discountRate, U.issued_at AS issuedAt, U.expired_at AS expiredAt, U.status AS status, DATEDIFF(U.expired_at, CURRENT_TIMESTAMP) AS dday FROM user_coupon U JOIN coupon C ON U.coupon_code = C.coupon_code WHERE 1=1 AND U.user_id = #{userId} AND C.coupon_type = 'COUPON'
AND U.status = #{status}
AND U.expired_at > CURRENT_TIMESTAMP ORDER BY U.expired_at ASC

SELECT IFNULL(COUNT(*), 0) FROM user_coupon U JOIN coupon C ON U.coupon_code = C.coupon_code WHERE 1=1 AND U.user_id = #{userId} AND C.coupon_type = 'COUPON'
AND U.status = #{status}
AND U.expired_at > CURRENT_TIMESTAMP ORDER BY U.expired_at ASC LIMIT #{pageSize} OFFSET #{offSet}

SELECT price
FROM pass_product
WHERE pass_no = #{passNo}

mapper.update:
UPDATE user_coupon
SET status = 'USED',
    used_at = NOW(),
    pay_no = #{payNo}
WHERE user_id = #{userId}
  AND coupon_code = #{couponCode}
  AND status = 'UNUSED'

mapper.select:
SELECT COALESCE(company_no, 0) AS companyNo
FROM company
WHERE user_id = #{userId}
